/** Reconstruct an AsSigningKey from a stored DB row. */
export async function loadActiveKey(row: AsSigningKeyRow): Promise<AsSigningKey> {
  const privateKey = await crypto.subtle.importKey(
    "jwk",
    row.private_jwk,
    { name: "ECDSA", namedCurve: "P-256" },
    false,
    ["sign"],
  );

  const publicJwk = {
    ...row.public_jwk,
    kid: row.kid,
    alg: "ES256",
    use: "sig",
  } as AsSigningKey["publicJwk"];

  stripPrivateKeyMaterial(publicJwk as Record<string, unknown>);

  return {
    kid: row.kid,
    algorithm: "ES256",
    publicJwk,
    privateKey,
  };
}

