329→/**
330→ * Obtain an OAuth2 JWT access token for MCP endpoints.
331→ * Requires a SurrealDB connection to skip consent screen.
332→ */
333→export async function getOAuthToken(
334→  baseUrl: string,
335→  surreal: Surreal,
336→  sessionHeaders: Record<string, string>,
337→  scopes: string = "graph:read graph:reason session:write offline_access",
338→): Promise<string> {
339→  // Trigger JWKS key generation if not yet done
340→  await fetch(`${baseUrl}/api/auth/jwks`);
341→
342→  const dcrRes = await fetch(`${baseUrl}/api/auth/oauth2/register`, {
343→    method: "POST",
344→    headers: { "Content-Type": "application/json" },
345→    body: JSON.stringify({
346→      client_name: `test-client-${Date.now()}`,
347→      redirect_uris: ["http://127.0.0.1:9999/callback"],
348→      grant_types: ["authorization_code", "refresh_token"],
349→      response_types: ["code"],
350→      token_endpoint_auth_method: "none",
351→    }),
352→  });
353→  if (!dcrRes.ok) throw new Error(`DCR failed: ${dcrRes.status} ${await dcrRes.text()}`);
354→
355→  const { client_id } = (await dcrRes.json()) as { client_id: string };
356→
357→  await surreal.query(`UPDATE oauthClient SET skipConsent = true WHERE clientId = $cid;`, {
358→    cid: client_id,
359→  });
360→
361→  const { verifier, challenge } = generatePkce();
362→  const authUrl = new URL(`${baseUrl}/api/auth/oauth2/authorize`);
363→  authUrl.searchParams.set("client_id", client_id);
364→  authUrl.searchParams.set("redirect_uri", "http://127.0.0.1:9999/callback");
365→  authUrl.searchParams.set("response_type", "code");
366→  authUrl.searchParams.set("scope", scopes);
367→  authUrl.searchParams.set("state", "test-state");
368→  authUrl.searchParams.set("code_challenge", challenge);
369→  authUrl.searchParams.set("code_challenge_method", "S256");
370→  authUrl.searchParams.set("resource", baseUrl);
371→
372→  const authRes = await fetch(authUrl.toString(), {
373→    headers: sessionHeaders,
374→    redirect: "manual",
375→  });
376→  if (authRes.status !== 302) throw new Error(`Authorize did not redirect: ${authRes.status}`);
377→
378→  const location = authRes.headers.get("location")!;
379→  const redirectUrl = new URL(location, baseUrl);
380→  const code = redirectUrl.searchParams.get("code") ?? "";
381→  if (!code) throw new Error(`No code in redirect: ${location}`);
382→
383→  const tokenRes = await fetch(`${baseUrl}/api/auth/oauth2/token`, {
384→    method: "POST",
385→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
386→    body: new URLSearchParams({
387→      grant_type: "authorization_code",
388→      code,
389→      redirect_uri: "http://127.0.0.1:9999/callback",
390→      client_id,
391→      code_verifier: verifier,
392→      resource: baseUrl,
393→    }),
394→  });
395→  if (!tokenRes.ok) throw new Error(`Token exchange failed: ${tokenRes.status} ${await tokenRes.text()}`);
396→
397→  const tokens = (await tokenRes.json()) as { access_token: string };
398→  return tokens.access_token;
399→}
400→
401→export type TestUserWithMcp = TestUser & {
402→  mcpHeaders: Record<string, string>;
403→};
404→
405→/**
406→ * Create a test user with both session cookie and OAuth MCP token.
407→ */
408→export async function createTestUserWithMcp(
409→  baseUrl: string,
410→  surreal: Surreal,
411→  suffix: string,
412→  scopes?: string,
413→): Promise<TestUserWithMcp> {
414→  const user = await createTestUser(baseUrl, suffix);
415→  const accessToken = await getOAuthToken(baseUrl, surreal, user.headers, scopes);
416→  return {
417→    ...user,
418→    mcpHeaders: { Authorization: `Bearer ${accessToken}` },
419→  };
420→}
