 30→  embeddingModel: openrouter.textEmbeddingModel(requireTestEnv("OPENROUTER_EMBEDDING_MODEL")),
 31→  embeddingDimension: Number(requireTestEnv("EMBEDDING_DIMENSION")),
 32→};
