 34→/** @deprecated Use `testAI` instead. */
 35→export const smokeAI = testAI;
 36→
 37→export type AcceptanceTestRuntime = {
 38→  baseUrl: string;
 39→  surreal: Surreal;
 40→  namespace: string;
 41→  database: string;
 42→  port: number;
 43→};
 44→
 45→/** @deprecated Use `AcceptanceTestRuntime` instead. */
 46→export type SmokeTestRuntime = AcceptanceTestRuntime;
 47→
 48→export type AcceptanceSuiteOptions = {
 49→  /** Extra env vars to set before the server boots (e.g. ORCHESTRATOR_MOCK_AGENT). */
 50→  env?: Record<string, string>;
 51→};
 52→
 53→const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
 54→const surrealUsername = process.env.SURREAL_USERNAME ?? "root";
 55→const surrealPassword = process.env.SURREAL_PASSWORD ?? "root";
 56→
 57→export function setupAcceptanceSuite(
 58→  suiteName: string,
 59→  options?: AcceptanceSuiteOptions,
 60→): () => AcceptanceTestRuntime {
 61→  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
 62→  const namespace = `accept_${runId}`;
 63→  const suiteSlug = suiteName
 64→    .toLowerCase()
 65→    .replace(/[^a-z0-9]+/g, "_")
 66→    .replace(/^_+|_+$/g, "");
 67→  const database = `${suiteSlug || "suite"}_${Math.floor(Math.random() * 100000)}`;
 68→
 69→  let runtime: AcceptanceTestRuntime | undefined;
 70→  let server: ReturnType<typeof Bun.serve> | undefined;
 71→  let runtimeSurreal: Surreal | undefined;
 72→  let analyticsSurreal: Surreal | undefined;
 73→  let inflight: InflightTracker | undefined;
 74→  let setupSucceeded = false;
 75→
 76→  beforeAll(async () => {
 77→    // Apply env overrides before server boot
 78→    if (options?.env) {
 79→      for (const [k, v] of Object.entries(options.env)) {
 80→        process.env[k] = v;
 81→      }
 82→    }
 83→
 84→    const surreal = new Surreal();
 85→    await withTimeout(() => surreal.connect(surrealUrl), 10_000, "connect to SurrealDB");
 86→    await withTimeout(
 87→      () => surreal.signin({ username: surrealUsername, password: surrealPassword }),
 88→      10_000,
 89→      "authenticate with SurrealDB",
 90→    );
 91→
 92→    await withTimeout(() => surreal.query(`DEFINE NAMESPACE ${namespace};`), 10_000, "define test namespace");
 93→    await withTimeout(() => surreal.use({ namespace }), 10_000, "switch to test namespace");
 94→    await withTimeout(() => surreal.query(`DEFINE DATABASE ${database};`), 10_000, "define test database");
 95→    await withTimeout(
 96→      () => surreal.use({ namespace, database }),
 97→      10_000,
 98→      "switch to test namespace/database",
 99→    );
100→
101→    const schemaSql = readFileSync(join(process.cwd(), "schema", "surreal-schema.surql"), "utf8");
102→    await withTimeout(() => surreal.query(schemaSql), 20_000, "apply schema");
103→
104→    // Reserve a port so betterAuth gets the real URL at init time
105→    const tempServer = Bun.serve({ port: 0, fetch: () => new Response() });
106→    const reservedPort = tempServer.port;
107→    tempServer.stop(true);
108→    const baseUrl = `http://127.0.0.1:${reservedPort}`;
109→
110→    const config: ServerConfig = {
111→      openRouterApiKey: requireTestEnv("OPENROUTER_API_KEY"),
112→      chatAgentModelId: requireTestEnv("CHAT_AGENT_MODEL"),
113→      extractionModelId: requireTestEnv("EXTRACTION_MODEL"),
114→      pmAgentModelId: process.env.PM_AGENT_MODEL?.trim() || requireTestEnv("EXTRACTION_MODEL"),
115→      analyticsAgentModelId: requireTestEnv("ANALYTICS_MODEL"),
116→      embeddingModelId: requireTestEnv("OPENROUTER_EMBEDDING_MODEL"),
117→      embeddingDimension: Number(requireTestEnv("EMBEDDING_DIMENSION")),
118→      extractionStoreThreshold: Number(requireTestEnv("EXTRACTION_STORE_THRESHOLD")),
119→      extractionDisplayThreshold: Number(requireTestEnv("EXTRACTION_DISPLAY_THRESHOLD")),
120→      surrealUrl,
121→      surrealUsername,
122→      surrealPassword,
123→      surrealNamespace: namespace,
124→      surrealDatabase: database,
125→      port: reservedPort,
126→      betterAuthSecret: process.env.BETTER_AUTH_SECRET ?? "smoke-test-secret-at-least-32-chars-long",
127→      betterAuthUrl: baseUrl,
128→      githubClientId: process.env.GITHUB_CLIENT_ID ?? "smoke-test-github-id",
129→      githubClientSecret: process.env.GITHUB_CLIENT_SECRET ?? "smoke-test-github-secret",
130→    };
131→
132→    const deps = await createRuntimeDependencies(config);
133→    runtimeSurreal = deps.surreal;
134→    analyticsSurreal = deps.analyticsSurreal;
135→    inflight = createInflightTracker();
136→
137→    const serverDeps: ServerDependencies = {
138→      config,
139→      surreal: deps.surreal,
140→      analyticsSurreal: deps.analyticsSurreal,
141→      auth: deps.auth,
142→      chatAgentModel: deps.chatAgentModel,
143→      extractionModel: deps.extractionModel,
144→      pmAgentModel: deps.pmAgentModel,
145→      analyticsAgentModel: deps.analyticsAgentModel,
146→      embeddingModel: deps.embeddingModel,
147→      sse: createSseRegistry(),
148→      inflight,
149→      asSigningKey: deps.asSigningKey,
150→      nonceCache: createNonceCache(),
