153→    server = createBrainServer(serverDeps);
154→    const port = server.port;
155→
156→    runtime = { baseUrl, surreal, namespace, database, port };
157→    setupSucceeded = true;
158→  }, 60_000);
159→
160→  afterAll(async () => {
161→    // Drain fire-and-forget work (e.g. webhook extraction) before closing DB
162→    if (inflight) {
163→      await inflight.drain(15_000);
