165→
166→    if (server) {
167→      server.stop(true);
168→    }
169→
170→    if (runtimeSurreal) {
171→      await runtimeSurreal.close().catch(() => undefined);
172→    }
173→    if (analyticsSurreal) {
174→      await analyticsSurreal.close().catch(() => undefined);
175→    }
176→
177→    if (!runtime) {
178→      return;
179→    }
180→
181→    if (setupSucceeded && !process.env.SMOKE_KEEP_DB) {
182→      try {
183→        await withTimeout(() => runtime!.surreal.query(`REMOVE DATABASE ${database};`), 10_000, "remove test database");
184→      } catch {
185→        // Best effort cleanup.
186→      }
187→
188→      try {
189→        await withTimeout(() => runtime!.surreal.query(`REMOVE NAMESPACE ${namespace};`), 10_000, "remove test namespace");
190→      } catch {
191→        // Best effort cleanup.
192→      }
193→    }
194→
195→    await withTimeout(() => runtime!.surreal.close(), 2_000, "close SurrealDB").catch(() => undefined);
196→  }, 20_000);
197→
198→  return () => {
199→    if (!runtime) {
200→      throw new Error("Acceptance runtime requested before suite setup completed");
201→    }
