206→/** @deprecated Use `setupAcceptanceSuite` instead. */
207→export const setupSmokeSuite = setupAcceptanceSuite;
208→
209→// ---------------------------------------------------------------------------
210→// Auth Helpers
211→// ---------------------------------------------------------------------------
212→
213→export type TestUser = {
214→  headers: Record<string, string>;
215→};
216→
217→export async function createTestUser(baseUrl: string, suffix: string): Promise<TestUser> {
218→  const email = `test-${Date.now()}-${suffix}@test.local`;
219→  const response = await fetch(`${baseUrl}/api/auth/sign-up/email`, {
220→    method: "POST",
221→    headers: { "Content-Type": "application/json" },
222→    body: JSON.stringify({ name: "Test User", email, password: "test-password-123" }),
223→    redirect: "manual",
224→  });
225→
226→  if (!response.ok) {
227→    const body = await response.text();
228→    throw new Error(`Failed to create test user (${response.status}): ${body}`);
229→  }
230→
231→  const setCookie = response.headers.getSetCookie();
232→  if (!setCookie || setCookie.length === 0) {
233→    throw new Error("Sign-up did not return session cookies");
234→  }
235→
236→  const cookieHeader = setCookie.map((c) => c.split(";")[0]).join("; ");
237→  return { headers: { Cookie: cookieHeader } };
238→}
239→
240→// ---------------------------------------------------------------------------
241→// SSE Helpers
242→// ---------------------------------------------------------------------------
243→
244→export async function collectSseEvents<T extends { type: string }>(streamUrl: string, timeoutMs: number): Promise<T[]> {
245→  const response = await fetch(streamUrl, { headers: { Accept: "text/event-stream" } });
246→  if (!response.ok || !response.body) {
247→    throw new Error(`Failed to open SSE stream (${response.status})`);
248→  }
249→
250→  const reader = response.body.getReader();
251→  const decoder = new TextDecoder();
252→  const events: T[] = [];
253→  let buffer = "";
254→
255→  const timeout = setTimeout(() => {
256→    void reader.cancel();
257→  }, timeoutMs);
258→
259→  try {
260→    while (true) {
261→      const { value, done } = await reader.read();
262→      if (done) {
263→        break;
264→      }
265→
266→      buffer += decoder.decode(value, { stream: true });
267→      const segments = buffer.split("\n\n");
268→      buffer = segments.pop() ?? "";
269→
270→      for (const segment of segments) {
271→        const dataLine = segment.split("\n").find((line) => line.startsWith("data: "));
272→        if (!dataLine) {
273→          continue;
274→        }
275→
276→        const event = JSON.parse(dataLine.slice("data: ".length)) as T;
277→        events.push(event);
278→
279→        if (event.type === "error") {
280→          const errorText = (event as { error?: string }).error;
281→          throw new Error(`SSE error event: ${errorText ?? "unknown error"}`);
282→        }
283→
284→        if (event.type === "done") {
285→          return events;
286→        }
287→      }
288→    }
289→  } finally {
290→    clearTimeout(timeout);
291→    reader.releaseLock();
292→  }
293→
294→  return events;
295→}
296→
297→// ---------------------------------------------------------------------------
298→// HTTP Helpers
299→// ---------------------------------------------------------------------------
300→
301→export async function fetchJson<T>(url: string, init?: RequestInit): Promise<T> {
302→  const response = await fetch(url, init);
303→  if (!response.ok) {
304→    const body = await response.text();
305→    throw new Error(`Request failed (${response.status}) ${url}: ${body}`);
306→  }
307→
308→  return (await response.json()) as T;
309→}
310→
311→export async function fetchRaw(url: string, init?: RequestInit): Promise<Response> {
312→  return fetch(url, init);
313→}
