 */
export async function getTestUserBearerToken(
  baseUrl: string,
  surreal: Surreal,
  user: BaseTestUser,
  scopes?: string,
): Promise<TestUserWithToken> {
  const accessToken = await getOAuthToken(
    baseUrl,
    surreal,
    user.headers,
    scopes ?? MCP_SCOPES,
  );

  return {
    ...user,
    accessToken,
    bearerHeaders: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${accessToken}`,
    },
  };
}

