102→/**
103→ * Creates a draft intent directly in the database.
104→ * Used as a Given-step precondition for scenarios that start
105→ * with an intent already in draft status.
106→ */
107→export async function createDraftIntent(
108→  surreal: Surreal,
109→  workspaceId: string,
110→  requesterId: string,
111→  opts: CreateIntentOptions,
112→): Promise<{ intentId: string; intentRecord: RecordId<"intent"> }> {
113→  const intentId = `intent-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
114→  const intentRecord = new RecordId("intent", intentId);
115→  const workspaceRecord = new RecordId("workspace", workspaceId);
116→  const requesterRecord = new RecordId("identity", requesterId);
117→
118→  // Create trace record for the intent
119→  const traceId = `trace-${intentId}`;
120→  const traceRecord = new RecordId("trace", traceId);
121→  await surreal.query(`CREATE $trace CONTENT $content;`, {
122→    trace: traceRecord,
123→    content: {
124→      type: "intent_submission",
125→      actor: requesterRecord,
126→      workspace: workspaceRecord,
127→      created_at: new Date(),
128→    },
129→  });
130→
131→  const content: Record<string, unknown> = {
132→    goal: opts.goal,
133→    reasoning: opts.reasoning,
134→    status: "draft",
135→    priority: opts.priority ?? 50,
136→    action_spec: opts.action_spec,
137→    trace_id: traceRecord,
138→    requester: requesterRecord,
139→    workspace: workspaceRecord,
140→    created_at: new Date(),
141→  };
142→
143→  if (opts.budget_limit) {
144→    content.budget_limit = opts.budget_limit;
145→  }
146→
147→  await surreal.query(`CREATE $intent CONTENT $content;`, {
148→    intent: intentRecord,
149→    content,
150→  });
151→
152→  // Link to originating task if provided
153→  if (opts.taskId) {
154→    const taskRecord = new RecordId("task", opts.taskId);
155→    await surreal.query(
156→      `RELATE $intent->triggered_by->$task SET created_at = time::now();`,
157→      { intent: intentRecord, task: taskRecord },
158→    );
159→  }
160→
161→  return { intentId, intentRecord };
162→}
