327→      body: JSON.stringify({ intent_id: intentId }),
328→    },
329→  );
330→}
331→
332→/**
333→ * Polls until an intent reaches the target status or times out.
334→ * Used to wait for async evaluation pipeline (SurrealQL EVENT -> evaluate -> status update).
335→ */
336→export async function waitForIntentStatus(
337→  surreal: Surreal,
338→  intentId: string,
339→  targetStatus: IntentStatus | IntentStatus[],
340→  timeoutMs = 30_000,
341→): Promise<IntentStatus> {
342→  const targets = Array.isArray(targetStatus) ? targetStatus : [targetStatus];
343→  const start = Date.now();
344→
345→  while (Date.now() - start < timeoutMs) {
346→    const current = await getIntentStatus(surreal, intentId);
347→    if (targets.includes(current)) {
348→      return current;
349→    }
350→    await Bun.sleep(250);
351→  }
352→
353→  const finalStatus = await getIntentStatus(surreal, intentId);
354→  throw new Error(
355→    `Intent ${intentId} did not reach ${targets.join("|")} within ${timeoutMs}ms. ` +
356→    `Current status: ${finalStatus}`,
357→  );
358→}
359→
360→/**
361→ * Simulates the evaluation endpoint completing (for tests where the
362→ * SurrealQL EVENT may not fire in the test environment).
363→ * Directly updates the intent with an evaluation result and new status.
364→ */
365→export async function simulateEvaluation(
366→  surreal: Surreal,
367→  intentId: string,
368→  evaluation: {
369→    decision: "APPROVE" | "REJECT";
370→    risk_score: number;
371→    reason: string;
372→    policy_only?: boolean;
373→  },
374→  resultStatus: IntentStatus,
375→): Promise<void> {
376→  const intentRecord = new RecordId("intent", intentId);
377→  const evalContent = {
378→    decision: evaluation.decision,
379→    risk_score: evaluation.risk_score,
380→    reason: evaluation.reason,
381→    evaluated_at: new Date(),
382→    policy_only: evaluation.policy_only ?? false,
383→  };
384→
385→  const updates: Record<string, unknown> = {
386→    status: resultStatus,
387→    evaluation: evalContent,
388→    updated_at: new Date(),
389→  };
390→
391→  // If entering veto window, set expiry
392→  if (resultStatus === "pending_veto") {
393→    const expiresAt = new Date(Date.now() + 5 * 60 * 1000); // 5 min default
394→    updates.veto_expires_at = expiresAt;
395→  }
396→
397→  await surreal.query(`UPDATE $intent MERGE $updates;`, {
398→    intent: intentRecord,
399→    updates,
400→  });
401→}
402→
403→/**
404→ * Queries the identity record for a user to get the identity ID.
405→ * Needed because intent.requester links to identity, not user.
406→ */
407→export async function getIdentityId(
408→  surreal: Surreal,
409→): Promise<string> {
410→  const rows = (await surreal.query(
411→    `SELECT id FROM identity LIMIT 1;`,
412→  )) as Array<Array<{ id: RecordId<"identity"> }>>;
413→  const result = rows[0]?.[0];
414→  if (!result) {
415→    throw new Error("No identity found -- create a test user first");
416→  }
417→  return result.id.id as string;
418→}
419→
420→/**
421→ * Creates a test identity directly in the database.
422→ * Used when we need an identity record without going through auth.
423→ */
424→export async function createTestIdentity(
425→  surreal: Surreal,
426→  name: string,
427→  type: "human" | "agent" = "agent",
428→  workspaceId?: string,
429→): Promise<string> {
430→  const identityId = `id-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
431→  const identityRecord = new RecordId("identity", identityId);
432→
433→  const content: Record<string, unknown> = {
434→    name,
435→    type,
436→    created_at: new Date(),
437→  };
438→
439→  if (workspaceId) {
440→    content.workspace = new RecordId("workspace", workspaceId);
441→  }
442→
443→  await surreal.query(`CREATE $identity CONTENT $content;`, {
444→    identity: identityRecord,
445→    content,
446→  });
447→  return identityId;
448→}
449→
450→/**
451→ * Wires the SurrealQL EVENT that fires when an intent transitions to
452→ * pending_auth. The EVENT calls http::post to the real test server's
453→ * evaluate endpoint, enabling true E2E testing of the async evaluation flow.
454→ *
455→ * Callback host can be overridden via INTENT_EVAL_CALLBACK_HOST.
456→ * Call this in beforeAll after the test server has booted.
457→ */
458→export async function wireIntentEvaluationEvent(
459→  surreal: Surreal,
460→  port: number,
461→): Promise<void> {
462→  const configuredHost = process.env.INTENT_EVAL_CALLBACK_HOST?.trim();
463→  const candidateHosts = configuredHost && configuredHost.length > 0
464→    ? [configuredHost]
465→    : ["127.0.0.1", "host.docker.internal"];
466→
467→  let baseUrl: string | undefined;
468→  let lastError = "";
469→
470→  for (const host of candidateHosts) {
471→    const candidateBaseUrl = `http://${host}:${port}`;
472→
473→    try {
474→      await surreal.query(`RETURN http::head($url);`, {
475→        url: `${candidateBaseUrl}/healthz`,
476→      });
477→      baseUrl = candidateBaseUrl;
478→      break;
479→    } catch (error) {
480→      lastError = error instanceof Error ? error.message : String(error);
481→    }
482→  }
483→
484→  if (!baseUrl) {
485→    throw new Error(
486→      `Unable to reach acceptance server from SurrealDB for intent callback. ` +
487→      `Tried hosts: ${candidateHosts.join(", ")} on port ${port}. ` +
488→      `Last error: ${lastError}`,
489→    );
490→  }
491→
492→  await surreal.query(`
493→    DEFINE EVENT OVERWRITE intent_pending_auth ON intent
494→      ASYNC
495→      RETRY 3
496→      WHEN $before.status != "pending_auth" AND $after.status = "pending_auth"
497→      THEN {
498→        http::post("${baseUrl}/api/intents/" + <string> meta::id($after.id) + "/evaluate", $after)
499→      };
500→  `);
501→}
502→

