 74→      client_name: "intent-test-client",
 75→      redirect_uris: ["http://127.0.0.1:9999/callback"],
 76→      grant_types: ["authorization_code", "refresh_token"],
 77→      response_types: ["code"],
 78→      token_endpoint_auth_method: "none",
 79→    }),
 80→  });
 81→  if (!dcrRes.ok) throw new Error(`DCR failed: ${dcrRes.status} ${await dcrRes.text()}`);
 82→
 83→  const { client_id } = (await dcrRes.json()) as { client_id: string };
 84→
 85→  await surreal.query(`UPDATE oauthClient SET skipConsent = true WHERE clientId = $cid;`, {
 86→    cid: client_id,
 87→  });
 88→
 89→  const { verifier, challenge } = generatePkce();
 90→  const authUrl = new URL(`${baseUrl}/api/auth/oauth2/authorize`);
 91→  authUrl.searchParams.set("client_id", client_id);
 92→  authUrl.searchParams.set("redirect_uri", "http://127.0.0.1:9999/callback");
 93→  authUrl.searchParams.set("response_type", "code");
 94→  authUrl.searchParams.set("scope", "graph:read graph:reason offline_access");
 95→  authUrl.searchParams.set("state", "test-state");
 96→  authUrl.searchParams.set("code_challenge", challenge);
 97→  authUrl.searchParams.set("code_challenge_method", "S256");
 98→  authUrl.searchParams.set("resource", baseUrl);
 99→
100→  const authRes = await fetch(authUrl.toString(), {
101→    headers: sessionHeaders,
102→    redirect: "manual",
103→  });
104→  if (authRes.status !== 302) throw new Error(`Authorize did not redirect: ${authRes.status}`);
105→
106→  const location = authRes.headers.get("location")!;
107→  const redirectUrl = new URL(location, baseUrl);
108→  const code = redirectUrl.searchParams.get("code") ?? "";
109→  if (!code) throw new Error(`No code in redirect: ${location}`);
110→
111→  const tokenRes = await fetch(`${baseUrl}/api/auth/oauth2/token`, {
112→    method: "POST",
113→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
114→    body: new URLSearchParams({
115→      grant_type: "authorization_code",
116→      code,
117→      redirect_uri: "http://127.0.0.1:9999/callback",
118→      client_id,
119→      code_verifier: verifier,
120→      resource: baseUrl,
121→    }),
122→  });
123→  if (!tokenRes.ok) throw new Error(`Token exchange failed: ${tokenRes.status} ${await tokenRes.text()}`);
124→
125→  const tokens = (await tokenRes.json()) as { access_token: string };
126→  return tokens.access_token;
127→}
