 51→/** Register an OAuth client via DCR and get tokens via the authorization flow */
 52→async function getOAuthTokens(
 53→  baseUrl: string,
 54→  surreal: import("surrealdb").Surreal,
 55→  sessionHeaders: Record<string, string>,
 56→  scopes: string,
 57→): Promise<{
 58→  clientId: string;
 59→  accessToken: string;
 60→  refreshToken: string;
 61→  expiresIn: number;
 62→}> {
 63→  // 1. Register a public client
 64→  const dcrRes = await fetch(`${baseUrl}/api/auth/oauth2/register`, {
 65→    method: "POST",
 66→    headers: { "Content-Type": "application/json" },
 67→    body: JSON.stringify({
 68→      client_name: "test-client",
 69→      redirect_uris: ["http://127.0.0.1:9999/callback"],
 70→      grant_types: ["authorization_code", "refresh_token"],
 71→      response_types: ["code"],
 72→      token_endpoint_auth_method: "none",
 73→    }),
 74→  });
 75→
 76→  if (!dcrRes.ok) {
 77→    throw new Error(`DCR failed: ${dcrRes.status} ${await dcrRes.text()}`);
 78→  }
 79→
 80→  const { client_id } = await dcrRes.json() as { client_id: string };
 81→
 82→  // Skip consent for test clients (authorize endpoint checks skip_consent on the client record)
 83→  await surreal.query(
 84→    `UPDATE oauthClient SET skipConsent = true WHERE clientId = $cid;`,
 85→    { cid: client_id },
 86→  );
 87→
 88→  // 2. Get authorization code with PKCE (required for public clients)
 89→  const { verifier, challenge } = generatePkce();
 90→  const authUrl = new URL(`${baseUrl}/api/auth/oauth2/authorize`);
 91→  authUrl.searchParams.set("client_id", client_id);
 92→  authUrl.searchParams.set("redirect_uri", "http://127.0.0.1:9999/callback");
 93→  authUrl.searchParams.set("response_type", "code");
 94→  authUrl.searchParams.set("scope", scopes);
 95→  authUrl.searchParams.set("state", "test-state");
 96→  authUrl.searchParams.set("code_challenge", challenge);
 97→  authUrl.searchParams.set("code_challenge_method", "S256");
 98→  // Pass resource so better-auth issues a JWT access token (not opaque)
 99→  authUrl.searchParams.set("resource", baseUrl);
100→
101→  const authRes = await fetch(authUrl.toString(), {
102→    headers: sessionHeaders,
103→    redirect: "manual",
104→  });
105→
106→  if (authRes.status !== 302) {
107→    const body = await authRes.text();
108→    throw new Error(`Authorize did not redirect: ${authRes.status} body=${body} headers=${JSON.stringify(Object.fromEntries(authRes.headers.entries()))}`);
109→  }
110→
111→  const location = authRes.headers.get("location");
112→  if (!location) throw new Error("No location header in auth redirect");
113→  const redirectUrl = new URL(location, baseUrl);
114→  const code = redirectUrl.searchParams.get("code") ?? "";
115→  const error = redirectUrl.searchParams.get("error");
116→  if (!code) throw new Error(`No code in redirect: ${location} (error=${error})`);
117→
118→  // 3. Exchange code for tokens
119→  const tokenRes = await fetch(`${baseUrl}/api/auth/oauth2/token`, {
120→    method: "POST",
121→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
122→    body: new URLSearchParams({
123→      grant_type: "authorization_code",
124→      code,
125→      redirect_uri: "http://127.0.0.1:9999/callback",
126→      client_id,
127→      code_verifier: verifier,
128→      resource: baseUrl,
129→    }),
130→  });
131→
132→  if (!tokenRes.ok) {
133→    throw new Error(`Token exchange failed: ${tokenRes.status} ${await tokenRes.text()}`);
134→  }
135→
136→  const tokens = await tokenRes.json() as {
137→    access_token: string;
138→    refresh_token: string;
139→    expires_in: number;
140→    token_type: string;
141→  };
142→
143→  return {
144→    clientId: client_id,
145→    accessToken: tokens.access_token,
146→    refreshToken: tokens.refresh_token,
147→    expiresIn: tokens.expires_in,
148→  };
149→}
