138→              headers: { "Content-Type": "application/json" },
139→              body: JSON.stringify({ email: "cli-init-test@example.com", password: "test-password-123!" }),
140→            });
141→            const signInData = (await signInRes.json()) as { token: string };
142→            const cookies = signInRes.headers.getSetCookie();
143→            const sessionCookie = cookies.find((c) => c.startsWith("better-auth.session_token="));
144→            const token = sessionCookie
145→              ? decodeURIComponent(sessionCookie.split("=")[1].split(";")[0])
146→              : signInData.token;
147→
148→            // Hit the authorize endpoint — server redirects to the callback URL with the code
149→            const authRes = await fetch(url, {
150→              headers: { Cookie: `better-auth.session_token=${token}` },
151→              redirect: "manual",
152→            });
153→
154→            if (authRes.status !== 302) {
155→              throw new Error(`Authorize did not redirect: ${authRes.status}`);
156→            }
157→
158→            // Follow the redirect to setupAuth's local callback server
159→            const location = authRes.headers.get("location")!;
160→            await fetch(location);
161→          } catch (err) {
162→            console.error("openUrl simulation failed:", err);
163→          }
164→        })();
165→      },
166→    });
167→
168→    // 5. Verify config was saved
169→    const configPath = join(configDir, "config.json");
170→    const config = JSON.parse(readFileSync(configPath, "utf-8")) as BrainGlobalConfig;
171→
172→    expect(config.server_url).toBe(baseUrl);
173→    expect(config.repos[gitRoot]).toBeDefined();
174→
175→    const repo = config.repos[gitRoot];
176→    expect(repo.workspace).toBe(workspaceId);
177→    expect(repo.client_id).toBeTruthy();
178→    expect(repo.access_token).toBeTruthy();
179→    expect(repo.refresh_token).toBeTruthy();
180→    expect(repo.token_expires_at).toBeGreaterThan(Math.floor(Date.now() / 1000));
181→
182→    // 6. Verify the access token actually works on an MCP route
183→    const mcpRes = await fetch(`${baseUrl}/api/mcp/${workspaceId}/projects`, {
184→      headers: { Authorization: `Bearer ${repo.access_token}` },
185→    });
186→    expect(mcpRes.status).toBe(200);
187→  }, 60_000);
188→});
