332→/**
333→ * Polls until an intent reaches the target status or times out.
334→ * Used to wait for async evaluation pipeline (SurrealQL EVENT -> evaluate -> status update).
335→ */
336→export async function waitForIntentStatus(
337→  surreal: Surreal,
338→  intentId: string,
339→  targetStatus: IntentStatus | IntentStatus[],
340→  timeoutMs = 30_000,
341→): Promise<IntentStatus> {
342→  const targets = Array.isArray(targetStatus) ? targetStatus : [targetStatus];
343→  const start = Date.now();
344→
345→  while (Date.now() - start < timeoutMs) {
346→    const current = await getIntentStatus(surreal, intentId);
347→    if (targets.includes(current)) {
348→      return current;
349→    }
350→    await Bun.sleep(250);
351→  }
352→
353→  const finalStatus = await getIntentStatus(surreal, intentId);
354→  throw new Error(
355→    `Intent ${intentId} did not reach ${targets.join("|")} within ${timeoutMs}ms. ` +
356→    `Current status: ${finalStatus}`,
357→  );
358→}
