450→/**
451→ * Wires the SurrealQL EVENT that fires when an intent transitions to
452→ * pending_auth. The EVENT calls http::post to the real test server's
453→ * evaluate endpoint, enabling true E2E testing of the async evaluation flow.
454→ *
455→ * Callback host can be overridden via INTENT_EVAL_CALLBACK_HOST.
456→ * Call this in beforeAll after the test server has booted.
457→ */
458→export async function wireIntentEvaluationEvent(
459→  surreal: Surreal,
460→  port: number,
461→): Promise<void> {
462→  const configuredHost = process.env.INTENT_EVAL_CALLBACK_HOST?.trim();
463→  const candidateHosts = configuredHost && configuredHost.length > 0
464→    ? [configuredHost]
465→    : ["127.0.0.1", "host.docker.internal"];
466→
467→  let baseUrl: string | undefined;
468→  let lastError = "";
469→
470→  for (const host of candidateHosts) {
471→    const candidateBaseUrl = `http://${host}:${port}`;
472→
473→    try {
474→      await surreal.query(`RETURN http::head($url);`, {
475→        url: `${candidateBaseUrl}/healthz`,
476→      });
477→      baseUrl = candidateBaseUrl;
478→      break;
479→    } catch (error) {
480→      lastError = error instanceof Error ? error.message : String(error);
481→    }
482→  }
483→
484→  if (!baseUrl) {
485→    throw new Error(
486→      `Unable to reach acceptance server from SurrealDB for intent callback. ` +
487→      `Tried hosts: ${candidateHosts.join(", ")} on port ${port}. ` +
488→      `Last error: ${lastError}`,
489→    );
490→  }
491→
492→  await surreal.query(`
493→    DEFINE EVENT OVERWRITE intent_pending_auth ON intent
494→      ASYNC
495→      RETRY 3
496→      WHEN $before.status != "pending_auth" AND $after.status = "pending_auth"
497→      THEN {
498→        http::post("${baseUrl}/api/intents/" + <string> meta::id($after.id) + "/evaluate", $after)
499→      };
500→  `);
501→}
