241→// ---------------------------------------------------------------------------
242→// SSE Helpers
243→// ---------------------------------------------------------------------------
244→
245→export async function collectSseEvents<T extends { type: string }>(streamUrl: string, timeoutMs: number): Promise<T[]> {
246→  const response = await fetch(streamUrl, { headers: { Accept: "text/event-stream" } });
247→  if (!response.ok || !response.body) {
248→    throw new Error(`Failed to open SSE stream (${response.status})`);
249→  }
250→
251→  const reader = response.body.getReader();
252→  const decoder = new TextDecoder();
253→  const events: T[] = [];
254→  let buffer = "";
255→
256→  const timeout = setTimeout(() => {
257→    void reader.cancel();
258→  }, timeoutMs);
259→
260→  try {
261→    while (true) {
262→      const { value, done } = await reader.read();
263→      if (done) {
264→        break;
265→      }
266→
267→      buffer += decoder.decode(value, { stream: true });
268→      const segments = buffer.split("\n\n");
269→      buffer = segments.pop() ?? "";
270→
271→      for (const segment of segments) {
272→        const dataLine = segment.split("\n").find((line) => line.startsWith("data: "));
273→        if (!dataLine) {
274→          continue;
275→        }
276→
277→        const event = JSON.parse(dataLine.slice("data: ".length)) as T;
278→        events.push(event);
279→
280→        if (event.type === "error") {
281→          const errorText = (event as { error?: string }).error;
282→          throw new Error(`SSE error event: ${errorText ?? "unknown error"}`);
283→        }
284→
285→        if (event.type === "done") {
286→          return events;
287→        }
288→      }
289→    }
290→  } finally {
291→    clearTimeout(timeout);
292→    reader.releaseLock();
293→  }
294→
295→  return events;
296→}
