330→/**
331→ * Obtain an OAuth2 JWT access token for MCP endpoints.
332→ * Requires a SurrealDB connection to skip consent screen.
333→ */
334→export async function getOAuthToken(
335→  baseUrl: string,
336→  surreal: Surreal,
337→  sessionHeaders: Record<string, string>,
338→  scopes: string = "graph:read graph:reason session:write offline_access",
339→): Promise<string> {
340→  // Trigger JWKS key generation if not yet done
341→  await fetch(`${baseUrl}/api/auth/jwks`);
342→
343→  const dcrRes = await fetch(`${baseUrl}/api/auth/oauth2/register`, {
344→    method: "POST",
345→    headers: { "Content-Type": "application/json" },
346→    body: JSON.stringify({
347→      client_name: `test-client-${Date.now()}`,
348→      redirect_uris: ["http://127.0.0.1:9999/callback"],
349→      grant_types: ["authorization_code", "refresh_token"],
350→      response_types: ["code"],
351→      token_endpoint_auth_method: "none",
352→    }),
353→  });
354→  if (!dcrRes.ok) throw new Error(`DCR failed: ${dcrRes.status} ${await dcrRes.text()}`);
355→
356→  const { client_id } = (await dcrRes.json()) as { client_id: string };
357→
358→  await surreal.query(`UPDATE oauthClient SET skipConsent = true WHERE clientId = $cid;`, {
359→    cid: client_id,
360→  });
361→
362→  const { verifier, challenge } = generatePkce();
363→  const authUrl = new URL(`${baseUrl}/api/auth/oauth2/authorize`);
364→  authUrl.searchParams.set("client_id", client_id);
365→  authUrl.searchParams.set("redirect_uri", "http://127.0.0.1:9999/callback");
366→  authUrl.searchParams.set("response_type", "code");
367→  authUrl.searchParams.set("scope", scopes);
368→  authUrl.searchParams.set("state", "test-state");
369→  authUrl.searchParams.set("code_challenge", challenge);
370→  authUrl.searchParams.set("code_challenge_method", "S256");
371→  authUrl.searchParams.set("resource", baseUrl);
372→
373→  const authRes = await fetch(authUrl.toString(), {
374→    headers: sessionHeaders,
375→    redirect: "manual",
376→  });
377→  if (authRes.status !== 302) throw new Error(`Authorize did not redirect: ${authRes.status}`);
378→
379→  const location = authRes.headers.get("location")!;
380→  const redirectUrl = new URL(location, baseUrl);
381→  const code = redirectUrl.searchParams.get("code") ?? "";
382→  if (!code) throw new Error(`No code in redirect: ${location}`);
383→
384→  const tokenRes = await fetch(`${baseUrl}/api/auth/oauth2/token`, {
385→    method: "POST",
386→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
387→    body: new URLSearchParams({
388→      grant_type: "authorization_code",
389→      code,
390→      redirect_uri: "http://127.0.0.1:9999/callback",
391→      client_id,
392→      code_verifier: verifier,
393→      resource: baseUrl,
394→    }),
395→  });
396→  if (!tokenRes.ok) throw new Error(`Token exchange failed: ${tokenRes.status} ${await tokenRes.text()}`);
397→
398→  const tokens = (await tokenRes.json()) as { access_token: string };
399→  return tokens.access_token;
400→}
