558→// ---------------------------------------------------------------------------
559→// DPoP Helpers
560→// ---------------------------------------------------------------------------
561→
562→async function generateDPoPKeyPair(): Promise<DPoPKeyPair> {
563→  const { publicKey, privateKey } = await crypto.subtle.generateKey(
564→    { name: "ECDSA", namedCurve: "P-256" },
565→    true,
566→    ["sign", "verify"],
567→  );
568→
569→  const publicJwk = await crypto.subtle.exportKey("jwk", publicKey);
570→  const thumbprint = await computeDPoPThumbprint(publicJwk);
571→
572→  return { privateKey, publicKey, publicJwk, thumbprint };
573→}
574→
575→async function computeDPoPThumbprint(publicJwk: JsonWebKey): Promise<string> {
576→  const thumbprintInput = JSON.stringify({
577→    crv: publicJwk.crv,
578→    kty: publicJwk.kty,
579→    x: publicJwk.x,
580→    y: publicJwk.y,
581→  });
582→
583→  const hashBuffer = await crypto.subtle.digest(
584→    "SHA-256",
585→    new TextEncoder().encode(thumbprintInput),
586→  );
587→
588→  return base64urlBytes(new Uint8Array(hashBuffer));
589→}
590→
591→async function createDPoPProof(
592→  keyPair: DPoPKeyPair,
593→  method: string,
594→  targetUri: string,
595→): Promise<string> {
596→  const header = {
597→    typ: "dpop+jwt" as const,
598→    alg: "ES256" as const,
599→    jwk: {
600→      kty: keyPair.publicJwk.kty,
601→      crv: keyPair.publicJwk.crv,
602→      x: keyPair.publicJwk.x,
603→      y: keyPair.publicJwk.y,
604→    },
605→  };
606→
607→  const payload = {
608→    jti: crypto.randomUUID(),
609→    htm: method,
610→    htu: targetUri,
611→    iat: Math.floor(Date.now() / 1000),
612→  };
613→
614→  const importedKey = await jose.importJWK(
615→    await crypto.subtle.exportKey("jwk", keyPair.privateKey),
616→    "ES256",
617→  );
618→
619→  return await new jose.SignJWT(payload)
620→    .setProtectedHeader(header)
621→    .sign(importedKey);
622→}
623→
624→function base64urlBytes(bytes: Uint8Array): string {
625→  const binary = String.fromCharCode(...bytes);
626→  return btoa(binary).replace(/\+/g, "-").replace(/\//g, "_").replace(/=/g, "");
627→}
