148→/**
149→ * Creates a task in assignable status via direct DB insertion.
150→ */
151→export async function createReadyTask(
152→  surreal: Surreal,
153→  workspaceId: string,
154→  options: {
155→    title: string;
156→    description?: string;
157→    status?: string;
158→    projectId?: string;
159→  },
160→): Promise<TestTask> {
161→  const taskId = `test-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
162→  const taskRecord = new RecordId("task", taskId);
163→  const workspaceRecord = new RecordId("workspace", workspaceId);
164→
165→  const content: Record<string, unknown> = {
166→    title: options.title,
167→    description: options.description ?? "Test task for orchestrator acceptance tests",
168→    status: options.status ?? "ready",
169→    created_at: new Date(),
170→    updated_at: new Date(),
171→    workspace: workspaceRecord,
172→  };
173→
174→  if (options.projectId) {
175→    const projectRecord = new RecordId("project", options.projectId);
176→    await surreal.query(
177→      `CREATE $task CONTENT $content;
178→       RELATE $task->belongs_to->$project SET added_at = time::now();`,
179→      { task: taskRecord, content: { ...content }, project: projectRecord },
180→    );
181→  } else {
182→    await surreal.query(`CREATE $task CONTENT $content;`, {
183→      task: taskRecord,
184→      content,
185→    });
186→  }
187→
188→  return { taskId, taskRecord };
189→}
