200→  const projectRecord = new RecordId("project", projectId);
201→  const workspaceRecord = new RecordId("workspace", workspaceId);
202→
203→  await surreal.query(
204→    `CREATE $project CONTENT $content;
205→     RELATE $ws->has_project->$project SET added_at = time::now();`,
206→    {
207→      project: projectRecord,
208→      ws: workspaceRecord,
209→      content: {
210→        name,
211→        status: "active",
212→        created_at: new Date(),
213→        updated_at: new Date(),
214→        workspace: workspaceRecord,
215→      },
216→    },
217→  );
218→
219→  return { projectId, projectRecord };
220→}
