341→/**
342→ * Queries task status directly from the database.
343→ */
344→export async function getTaskStatus(
345→  surreal: Surreal,
346→  taskId: string,
347→): Promise<string> {
348→  const taskRecord = new RecordId("task", taskId);
349→  const rows = (await surreal.query(
350→    `SELECT status FROM $task;`,
351→    { task: taskRecord },
352→  )) as Array<Array<{ status: string }>>;
353→  const result = rows[0]?.[0];
354→  if (!result) {
355→    throw new Error(`Task ${taskId} not found`);
356→  }
357→  return result.status;
358→}
