362→ */
363→export async function getAgentSessionsForTask(
364→  surreal: Surreal,
365→  taskId: string,
366→): Promise<
367→  Array<{
368→    id: RecordId;
369→    orchestrator_status: string;
370→    agent: string;
371→  }>
372→> {
373→  const taskRecord = new RecordId("task", taskId);
374→  const rows = (await surreal.query(
375→    `SELECT id, orchestrator_status, agent FROM agent_session WHERE task_id = $task;`,
376→    { task: taskRecord },
377→  )) as Array<
378→    Array<{ id: RecordId; orchestrator_status: string; agent: string }>
379→  >;
380→  return rows[0] ?? [];
381→}
